import{_ as o,o as a,c as e,a2 as i}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"アンチヨーヨーシステム (Anti Yo-Yo System)","description":"","frontmatter":{},"headers":[],"relativePath":"ja/advanced/anti-yoyo.md","filePath":"ja/advanced/anti-yoyo.md"}'),l={name:"ja/advanced/anti-yoyo.md"};function s(n,t,c,r,p,d){return a(),e("div",null,[...t[0]||(t[0]=[i('<h1 id="アンチヨーヨーシステム-anti-yo-yo-system" tabindex="-1"><i class="ph ph-arrows-clockwise"></i> アンチヨーヨーシステム (Anti Yo-Yo System) <a class="header-anchor" href="#アンチヨーヨーシステム-anti-yo-yo-system" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-arrows-clockwise&quot;&gt;&lt;/i&gt; アンチヨーヨーシステム (Anti Yo-Yo System)&quot;">​</a></h1><p>動的スケーリングシステムにおける最も厄介な問題の1つが、<strong>ヨーヨー効果 (Yo-Yo Effect)</strong>（または品質のピンポン）です。</p><h2 id="コアとなる問題" tabindex="-1"><i class="ph ph-warning-circle"></i> コアとなる問題 <a class="header-anchor" href="#コアとなる問題" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-warning-circle&quot;&gt;&lt;/i&gt; コアとなる問題&quot;">​</a></h2><p>インテリジェントな制御がない場合、システムは無限ループに陥ります：</p><ol><li>重いシーンによりFPSが低下します。</li><li>プラグインはグラフィック品質を下げます（例：解像度を減らします）。</li><li>負荷が減少し、FPSがベースラインを上回ります。</li><li>プラグインはパフォーマンスの余裕（Performance Headroom）があると判断し、グラフィック品質を最大まで回復させます。</li><li>FPSが再び低下します。このサイクルが繰り返されます。</li></ol><p>その結果、プレイヤーは絶え間ない品質のちらつき（Quality flickering）を経験することになります。シャドウが絶え間なく現れたり消えたりし、画像は1秒ごとにぼやけたり鮮明になったりします。</p><h2 id="webapの解決策-ペナルティロックアウト-penalty-lockout" tabindex="-1"><i class="ph ph-shield-check"></i> WebAPの解決策：ペナルティロックアウト (Penalty Lockout) <a class="header-anchor" href="#webapの解決策-ペナルティロックアウト-penalty-lockout" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-shield-check&quot;&gt;&lt;/i&gt; WebAPの解決策：ペナルティロックアウト (Penalty Lockout)&quot;">​</a></h2><p>私たちは、プラグイン設定の2つのパラメータに基づいて構築されたペナルティロックアウトの概念を実装することにより、この問題を完全に根絶しました。</p><p>プラグインがグラフィック品質を<em>向上</em>させると、非表示のタイマーである <strong>Detection Window</strong>（例：15秒）が開始されます。この期間中、インデクサー（Indexer）はフレームの安定性を注意深く監視します。</p><p>この時間枠内にFPSが突然低下した場合、システムは決定的な結論を導き出します：<em>«以前のグラフィックの向上は間違いでした。デバイスはこのレベルを長期的に維持することはできません。»</em></p><p><strong>ペナルティが適用されます：</strong></p><ol><li>プラグインは直ちに品質を再び低下させます。</li><li>厳格な <strong>Penalty Lockout Duration</strong>（例：60秒）が適用されます。</li><li>この1分間、プラグインはグラフィック品質を上げようとすることを<strong>断固として禁じられます</strong>。たとえFPSが急上昇してプロセッサがアイドル状態になったとしてもです。</li></ol><div class="tip custom-block"><p class="custom-block-title">セッションロック (Session Lock)</p><p>ゲームのダイナミクスに負荷の急増の波があり、最初の低下の後に品質が元に戻らないことを好む場合は、<strong>Penalty Lockout Duration</strong> フィールドに非常に大きな値（例：10分の場合は <code>600</code>、1時間の場合は <code>3600</code>）を指定するだけです。これにより、ゲームセッションが終了するまで、一貫した低レベルのグラフィックに効果的にロックされます。</p></div><div class="info custom-block"><p class="custom-block-title">流暢さ (Fluency) の優先</p><p>ペナルティは、レンダリングを向上させようとする試みのみをブロックします。プレイヤーがさらに重いシーンに入り、FPSが臨界しきい値を下回った場合、プラグインは緊急手段として依然として品質を低下させることができます。システムは常に、ビジュアルよりもゲームプレイの流暢さを優先します。</p></div>',14)])])}const m=o(l,[["render",s]]);export{u as __pageData,m as default};
